mapper.select:
/* com.shop.mapper.product.productContentList.selectProdContentList */
SELECT
      A.ID AS id
    , A.NEWS_TITLE AS newsTitle
    , A.NEWS_SUB_TITLE AS newsSubTitle
    , A.NEWS_CONTENTS AS newsContents
    , A.FILE_ID AS fileId
    , (SELECT COUNT(1) FROM TB_FILE_DET X WHERE X.FILE_ID = A.FILE_ID AND X.DEL_YN = 'N') AS imageCnt
    , (SELECT COUNT(1) FROM TB_CONTENTS_PRODUCT X WHERE X.CONTENTS_ID = A.ID AND DEL_YN = 'N') AS productCnt
FROM TB_CONTENTS A

    AND A.DEL_YN = 'N'
    AND A.NEWS_TYPE = #{filter.newsType}
    AND A.PARTNER_ID = #{filter.partnerId}

        AND A.NEWS_TITLE = #{filter.newsTitle}


        AND (
        A.ID > #{filter.lastId}
        )


ORDER BY A.ID
LIMIT #{pageRowCount} + 1;

mapper.update:
/* com.shop.mapper.product.productContentList.deleteProductContents */
UPDATE TB_CONTENTS
SET DEL_YN = 'Y'
  , UPD_USER = #{updUser}
  , UPD_TM = NOW()
WHERE ID = #{id}

mapper.select:
/* com.shop.mapper.product.productContentList.selectProductInfoList */ SELECT TP.ID AS id , TP.PROD_CD AS prodCd , TP.PROD_TP AS prodTp , TP.PROD_NM AS prodNm , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm , FN_GET_CODE('90011', TP.PROD_DET_TP) prodDetTpNm , FN_GET_PRODUCT_COLORS(TP.ID) AS prodColors , FN_GET_PRODUCT_SIZES(TP.ID) AS prodSizes , TP.DISCOUNT_RATE AS discountRate , (SELECT COUNT(1) FROM TB_CONTENTS_PRODUCT CP WHERE CP.PRODUCT_ID = TP.ID AND CP.DEL_YN = 'N') AS contentsProductCnt FROM TB_PRODUCT TP
AND TP.DEL_YN = 'N' AND NOT EXISTS (SELECT 1 FROM TB_CONTENTS_PRODUCT CP WHERE CP.PRODUCT_ID = TP.ID AND CP.CONTENTS_ID = #{filter.contentsId})
AND TP.PROD_NM LIKE CONCAT('%' ,#{filter.prodNm} ,'%')
AND ( TP.ID > #{filter.lastId} )
ORDER BY TP.ID LIMIT #{pageRowCount} + 1;

/* com.shop.mapper.product.productContentList.selectContentsProductInfoList */ SELECT TP.ID AS id , CP.ID AS contentsProductId , CP.SEQ AS contentsProductSeq , TP.PROD_NM AS prodNm , TP.SELL_AMT AS sellAmt , TP.REP_FILE_ID AS repFileId , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm , FN_GET_CODE('90011', TP.PROD_DET_TP) prodDetTpNm , FN_GET_PRODUCT_COLORS(TP.ID) AS prodColors , FN_GET_PRODUCT_SIZES(TP.ID) AS prodSizes , TP.DISCOUNT_RATE AS discountRate FROM TB_PRODUCT TP JOIN TB_CONTENTS_PRODUCT CP ON CP.PRODUCT_ID = TP.ID AND CP.DEL_YN = 'N'
AND TP.DEL_YN = 'N' AND CP.CONTENTS_ID = #{contentsId}
GROUP BY TP.ID, CP.ID ORDER BY CP.SEQ
